// Fora do claude.ai não existe window.storage — usamos localStorage do navegador no lugar.
// Atenção: cada navegador/dispositivo tem seu próprio localStorage, então os dados NÃO
// sincronizam automaticamente entre o celular da Carolina e o do Eliel (cada um vê só o que
// digitou no próprio aparelho).
if (typeof window !== "undefined" && !window.storage) {
  window.storage = {
    get: async (key) => {
      const v = localStorage.getItem(key);
      return v == null ? null : { value: v };
    },
    set: async (key, value) => {
      localStorage.setItem(key, value);
      return { value };
    },
  };
}
