function normalizarSegmentos(parsed) {
  // Este painel é dedicado a uma vendedora e um único segmento (Contabilidade) —
  // qualquer segmento antigo salvo é descartado, mantendo só os dados de cidade
  // que já existiam para Contabilidade.
  const segmentosAntigos = parsed.segmentos || {};
  const segmentos = {};
  const ordem = [];
  for (const nome of CURATED_SEGMENTOS) {
    segmentos[nome] = segmentosAntigos[nome] || {};
    ordem.push(nome);
  }
  return {
    segmentos,
    ordemSegmentos: ordem,
    vendedores: parsed.vendedores || [],
    atribuicoes: parsed.atribuicoes || {},
    historico: parsed.historico || [],
    meta: parsed.meta || 0,
    mensagens: parsed.mensagens || {},
  };
}

function emptyData() {
  return normalizarSegmentos({ segmentos: {}, ordemSegmentos: [], vendedores: [], atribuicoes: {}, historico: [], meta: 0, mensagens: {} });
}

function fmtRelTime(ts) {
  const diff = Date.now() - ts;
  const min = Math.floor(diff / 60000);
  if (min < 1) return "agora";
  if (min < 60) return `há ${min} min`;
  const h = Math.floor(min / 60);
  if (h < 24) return `há ${h}h`;
  const d = Math.floor(h / 24);
  if (d < 30) return `há ${d}d`;
  return new Date(ts).toLocaleDateString("pt-BR");
}

function fmtBRL(v) {
  if (!v) return "R$ 0";
  if (v >= 1000000) return "R$ " + (v / 1000000).toFixed(1) + "M";
  if (v >= 1000) return "R$ " + (v / 1000).toFixed(1) + "mil";
  return "R$ " + v.toLocaleString("pt-BR");
}

function chaveAtrib(seg, uf) {
  return seg + "|" + uf;
}

function StatusIcon({ status, size = 12 }) {
  if (status === "concluido") return <Check size={size} strokeWidth={3} />;
  if (status === "em_andamento") return <Clock size={size} />;
  return <CircleDashed size={size} />;
}

function defaultCidade() {
  return { empresas: "", fechados: "", valor: "", status: "nao_iniciado", obs: "", contatos: [], vendedor: "" };
}

// --- Contatos / disparo individual por WhatsApp (click-to-chat, sem automação) ---
function normalizaTelefone(raw) {
  let d = String(raw || "").replace(/\D/g, "");
  d = d.replace(/^0+/, "");
  if (d.length <= 11) d = "55" + d; // assume BR + DDD se não veio com código do país
  return d;
}

function montaLinkWhatsapp(telefone, mensagem) {
  const numero = normalizaTelefone(telefone);
  return `https://wa.me/${numero}?text=${encodeURIComponent(mensagem || "")}`;
}

function aplicaTemplate(template, contato, cidade, vendedor) {
  return String(template || "")
    .replaceAll("{nome}", contato.nome || "")
    .replaceAll("{cidade}", cidade || "")
    .replaceAll("{vendedor}", vendedor || "");
}

// Aceita uma linha por contato: "Nome, Telefone" ou "Nome; Telefone" ou só o telefone.
function parseContatosTexto(texto) {
  const linhas = String(texto || "").split("\n").map((l) => l.trim()).filter(Boolean);
  const out = [];
  for (const linha of linhas) {
    const partes = linha.split(/[,;\t]/).map((p) => p.trim()).filter(Boolean);
    let nome = "", telefone = "";
    if (partes.length >= 2) {
      // detecta qual parte é o telefone (mais dígitos)
      const digitos = partes.map((p) => p.replace(/\D/g, "").length);
      const idxTel = digitos.indexOf(Math.max(...digitos));
      telefone = partes[idxTel];
      nome = partes.filter((_, i) => i !== idxTel).join(" ");
    } else if (partes.length === 1) {
      telefone = partes[0];
    }
    const telDigitos = telefone.replace(/\D/g, "");
    if (telDigitos.length >= 8) {
      out.push({
        id: Math.random().toString(36).slice(2, 10),
        nome: nome || "",
        telefone,
        enviado: false,
        enviadoTs: null,
      });
    }
  }
  return out;
}

function numOrZero(v) {
  return Number(v) || 0;
}

function fmtPop(p) {
  if (!p) return "";
  if (p >= 1000000) return (p / 1000000).toFixed(p >= 10000000 ? 0 : 1) + "M hab.";
  if (p >= 1000) return Math.round(p / 1000) + "mil hab.";
  return p + " hab.";
}

export default function PainelProspeccao() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saveState, setSaveState] = useState("idle");
  const [segmentoAtual, setSegmentoAtual] = useState("Contabilidade");
  const [ufSelecionado, setUfSelecionado] = useState(null);
  const [novoSegmento, setNovoSegmento] = useState("");
  const [mostraNovoSegmento, setMostraNovoSegmento] = useState(false);
  const [hoveredUf, setHoveredUf] = useState(null);
  const [filtro, setFiltro] = useState("");
  const [sortBy, setSortBy] = useState("populacao");
  const [buscaGlobal, setBuscaGlobal] = useState("");
  const [buscaAberta, setBuscaAberta] = useState(false);
  const [tela, setTela] = useState("mapa");

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const res = await window.storage.get(STORAGE_KEY, false);
        if (mounted && res && res.value) {
          const parsed = JSON.parse(res.value);
          const normalizado = normalizarSegmentos(parsed);
          setData(normalizado);
          setSegmentoAtual(normalizado.ordemSegmentos?.[0] || "");
        } else if (mounted) {
          setData(emptyData());
        }
      } catch (e) {
        if (mounted) setData(emptyData());
      } finally {
        if (mounted) setLoading(false);
      }
    })();
    return () => { mounted = false; };
  }, []);

  const persist = useCallback(async (next) => {
    setData(next);
    setSaveState("saving");
    try {
      await window.storage.set(STORAGE_KEY, JSON.stringify(next), false);
      setSaveState("saved");
      setTimeout(() => setSaveState("idle"), 1000);
    } catch (e) {
      setSaveState("idle");
    }
  }, []);

  const resumoPorEstado = useMemo(() => {
    const out = {};
    if (!data) return out;
    const seg = data.segmentos?.[segmentoAtual] || {};
    for (const uf of Object.keys(seg)) {
      const cidades = Object.values(seg[uf]);
      const total = cidades.length;
      const concluidas = cidades.filter((c) => c.status === "concluido").length;
      const andamento = cidades.filter((c) => c.status === "em_andamento").length;
      const empresas = cidades.reduce((s, c) => s + numOrZero(c.empresas), 0);
      const fechados = cidades.reduce((s, c) => s + numOrZero(c.fechados), 0);
      const valor = cidades.reduce((s, c) => s + numOrZero(c.valor), 0);
      out[uf] = { total, concluidas, andamento, empresas, fechados, valor };
    }
    return out;
  }, [data, segmentoAtual]);

  const resumoGeral = useMemo(() => {
    const vals = Object.values(resumoPorEstado);
    return {
      cidades: vals.reduce((s, v) => s + v.total, 0),
      concluidas: vals.reduce((s, v) => s + v.concluidas, 0),
      empresas: vals.reduce((s, v) => s + v.empresas, 0),
      fechados: vals.reduce((s, v) => s + v.fechados, 0),
      valor: vals.reduce((s, v) => s + v.valor, 0),
      estados: vals.filter((v) => v.total > 0).length,
    };
  }, [resumoPorEstado]);

  const resumoPorSegmento = useMemo(() => {
    const out = {};
    if (!data) return out;
    for (const seg of data.ordemSegmentos) {
      const estados = data.segmentos[seg] || {};
      let cidades = 0, concluidas = 0, andamento = 0, empresas = 0, fechados = 0, valor = 0, estadosComReg = 0;
      for (const uf of Object.keys(estados)) {
        const arr = Object.values(estados[uf]);
        if (arr.length > 0) estadosComReg++;
        cidades += arr.length;
        concluidas += arr.filter((c) => c.status === "concluido").length;
        andamento += arr.filter((c) => c.status === "em_andamento").length;
        empresas += arr.reduce((s, c) => s + numOrZero(c.empresas), 0);
        fechados += arr.reduce((s, c) => s + numOrZero(c.fechados), 0);
        valor += arr.reduce((s, c) => s + numOrZero(c.valor), 0);
      }
      out[seg] = { cidades, concluidas, andamento, empresas, fechados, valor, estadosComReg };
    }
    return out;
  }, [data]);

  const resumoGlobal = useMemo(() => {
    const porVendedor = {};
    const porEstado = {};
    let totalEmpresas = 0, totalFechados = 0, totalValor = 0, totalCidades = 0, totalConcluidas = 0, totalAndamento = 0, totalNaoIniciado = 0;
    if (!data) return { porVendedor, porEstado, totalEmpresas, totalFechados, totalValor, totalCidades, totalConcluidas, totalAndamento, totalNaoIniciado };
    for (const seg of data.ordemSegmentos) {
      const estados = data.segmentos[seg] || {};
      for (const uf of Object.keys(estados)) {
        const arr = Object.values(estados[uf]);
        if (arr.length === 0) continue;
        const empresas = arr.reduce((s, c) => s + numOrZero(c.empresas), 0);
        const fechados = arr.reduce((s, c) => s + numOrZero(c.fechados), 0);
        const valor = arr.reduce((s, c) => s + numOrZero(c.valor), 0);
        const concluidas = arr.filter((c) => c.status === "concluido").length;
        const andamento = arr.filter((c) => c.status === "em_andamento").length;
        const naoIniciado = arr.length - concluidas - andamento;
        totalEmpresas += empresas;
        totalFechados += fechados;
        totalValor += valor;
        totalCidades += arr.length;
        totalConcluidas += concluidas;
        totalAndamento += andamento;
        totalNaoIniciado += naoIniciado;

        if (!porEstado[uf]) porEstado[uf] = { empresas: 0, fechados: 0, valor: 0, cidades: 0 };
        porEstado[uf].empresas += empresas;
        porEstado[uf].fechados += fechados;
        porEstado[uf].valor += valor;
        porEstado[uf].cidades += arr.length;

        const vendedor = data.atribuicoes[chaveAtrib(seg, uf)];
        if (vendedor) {
          if (!porVendedor[vendedor]) porVendedor[vendedor] = { empresas: 0, fechados: 0, valor: 0, cidades: 0 };
          porVendedor[vendedor].empresas += empresas;
          porVendedor[vendedor].fechados += fechados;
          porVendedor[vendedor].valor += valor;
          porVendedor[vendedor].cidades += arr.length;
        }
      }
    }
    return { porVendedor, porEstado, totalEmpresas, totalFechados, totalValor, totalCidades, totalConcluidas, totalAndamento, totalNaoIniciado };
  }, [data]);

  const resultadosBusca = useMemo(() => {
    if (!buscaGlobal.trim()) return [];
    const q = buscaGlobal.trim().toLowerCase();
    const out = [];
    for (const uf of Object.keys(MUNICIPIOS_BY_UF)) {
      for (const c of MUNICIPIOS_BY_UF[uf]) {
        if (c.n.toLowerCase().startsWith(q)) {
          out.push({ uf, nome: c.n });
          if (out.length >= 8) return out;
        }
      }
    }
    return out;
  }, [buscaGlobal]);

  if (loading || !data) {
    return (
      <div style={{ background: "#14181f" }} className="min-h-screen flex items-center justify-center text-slate-400">
        <Loader2 className="animate-spin mr-2" size={18} /> Carregando painel…
      </div>
    );
  }

  const addSegmento = () => {
    const nome = novoSegmento.trim();
    if (!nome) return;
    if (data.segmentos[nome]) { setSegmentoAtual(nome); setNovoSegmento(""); setMostraNovoSegmento(false); return; }
    const next = {
      segmentos: { ...data.segmentos, [nome]: {} },
      ordemSegmentos: [...data.ordemSegmentos, nome],
    };
    persist(next);
    setSegmentoAtual(nome);
    setNovoSegmento("");
    setMostraNovoSegmento(false);
  };

  const removeSegmento = (nome) => {
    const seg = { ...data.segmentos };
    delete seg[nome];
    const ordem = data.ordemSegmentos.filter((s) => s !== nome);
    const next = { segmentos: seg, ordemSegmentos: ordem };
    persist(next);
    if (segmentoAtual === nome) setSegmentoAtual(ordem[0] || "");
  };

  const updateCidade = (uf, cidade, patch) => {
    const seg = data.segmentos[segmentoAtual] || {};
    const ufData = seg[uf] || {};
    const atual = ufData[cidade] || defaultCidade();
    const merged = { ...atual, ...patch };
    const nextUfData = { ...ufData, [cidade]: merged };
    const eventos = [];
    if (patch.status && patch.status !== atual.status && patch.status === "concluido") {
      eventos.push({ ts: Date.now(), seg: segmentoAtual, uf, cidade, tipo: "concluido" });
    }
    if (patch.fechados !== undefined || patch.valor !== undefined) {
      const antesF = numOrZero(atual.fechados);
      const depoisF = numOrZero(patch.fechados !== undefined ? patch.fechados : atual.fechados);
      const antesV = numOrZero(atual.valor);
      const depoisV = numOrZero(patch.valor !== undefined ? patch.valor : atual.valor);
      const deltaF = depoisF - antesF;
      const deltaV = depoisV - antesV;
      if (deltaF > 0 || deltaV > 0) {
        eventos.push({ ts: Date.now(), seg: segmentoAtual, uf, cidade, tipo: "fechado", qtd: Math.max(0, deltaF), valorDelta: Math.max(0, deltaV) });
      }
    }
    const historico = eventos.length ? [...eventos, ...(data.historico || [])].slice(0, 300) : data.historico;
    const next = {
      ...data,
      segmentos: { ...data.segmentos, [segmentoAtual]: { ...seg, [uf]: nextUfData } },
      historico,
    };
    persist(next);
  };

  const exportarCSV = () => {
    const linhas = [["Segmento", "Estado", "Cidade", "Empresas", "Fechados", "Valor (R$)", "Status", "Vendedor", "Observacao"]];
    for (const seg of data.ordemSegmentos) {
      const estados = data.segmentos[seg] || {};
      for (const ufKey of Object.keys(estados)) {
        const vendedor = data.atribuicoes[chaveAtrib(seg, ufKey)] || "";
        for (const [cidade, info] of Object.entries(estados[ufKey])) {
          if (!info.empresas && !info.fechados && !info.valor && info.status === "nao_iniciado" && !info.obs) continue;
          linhas.push([
            seg,
            ufKey,
            cidade,
            numOrZero(info.empresas),
            numOrZero(info.fechados),
            numOrZero(info.valor),
            STATUS_OPTS.find((o) => o.v === info.status)?.label || info.status,
            vendedor,
            (info.obs || "").replace(/\n/g, " "),
          ]);
        }
      }
    }
    const csv = linhas.map((l) => l.map((v) => `"${String(v).replace(/"/g, '""')}"`).join(",")).join("\n");
    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "prospeccao_" + new Date().toISOString().slice(0, 10) + ".csv";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const estadoCor = (uf) => {
    const r = resumoPorEstado[uf];
    if (!r || r.total === 0) return "#232a36";
    if (r.concluidas === r.total) return "#3a6b4c";
    if (r.andamento > 0 || r.concluidas > 0) return "#8a6a34";
    return "#4a5468";
  };

  const irParaCidade = (uf, nome) => {
    setUfSelecionado(uf);
    setFiltro(nome);
    setBuscaAberta(false);
    setBuscaGlobal("");
  };

  const addVendedor = (nome) => {
    const n = nome.trim();
    if (!n || data.vendedores.includes(n)) return;
    persist({ ...data, vendedores: [...data.vendedores, n] });
  };

  const removeVendedor = (nome) => {
    const atrib = { ...data.atribuicoes };
    for (const k of Object.keys(atrib)) {
      if (atrib[k] === nome) delete atrib[k];
    }
    persist({ ...data, vendedores: data.vendedores.filter((v) => v !== nome), atribuicoes: atrib });
  };

  const updateMensagem = (seg, texto) => {
    persist({ ...data, mensagens: { ...data.mensagens, [seg]: texto } });
  };

  const atribuirVendedor = (seg, uf, vendedor) => {
    const atrib = { ...data.atribuicoes };
    const k = chaveAtrib(seg, uf);
    if (vendedor) atrib[k] = vendedor;
    else delete atrib[k];
    persist({ ...data, atribuicoes: atrib });
  };

  const setMeta = (valor) => {
    persist({ ...data, meta: numOrZero(valor) });
  };

  return (
    <div style={{ background: "#14181f", fontFamily: "'Inter', system-ui, sans-serif" }} className="min-h-screen text-slate-100">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;600;700&family=Inter:wght@400;500;600;700&display=swap');
        .mono { font-family: 'JetBrains Mono', ui-monospace, monospace; }
        input:focus, select:focus, textarea:focus, button:focus-visible { outline: 2px solid #e0a458; outline-offset: 1px; }
        ::-webkit-scrollbar { width: 8px; height: 8px; }
        ::-webkit-scrollbar-thumb { background: #2c3444; border-radius: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
      `}</style>

      <div style={{ borderBottom: "1px solid #232a36" }} className="px-5 py-4 sm:px-8 sm:py-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="mono text-[11px] tracking-widest text-[#e0a458] uppercase mb-1">Painel de prospecção</div>
            <h1 className="text-xl sm:text-2xl font-semibold text-slate-50">Mapa do Brasil por segmento</h1>
          </div>
          <div className="flex items-center gap-3">
            <button
              onClick={() => setTela("geral")}
              style={{
                background: tela === "geral" ? "#e0a458" : "#1c222c",
                color: tela === "geral" ? "#14181f" : "#c3cad6",
                border: "1px solid " + (tela === "geral" ? "#e0a458" : "#2c3444"),
              }}
              className="px-3 py-1.5 rounded-full text-sm font-medium flex items-center gap-1.5"
            >
              <LayoutDashboard size={13} /> Painel geral
            </button>
            <button
              onClick={() => setTela("vendedores")}
              style={{
                background: tela === "vendedores" ? "#e0a458" : "#1c222c",
                color: tela === "vendedores" ? "#14181f" : "#c3cad6",
                border: "1px solid " + (tela === "vendedores" ? "#e0a458" : "#2c3444"),
              }}
              className="px-3 py-1.5 rounded-full text-sm font-medium flex items-center gap-1.5"
            >
              <Users size={13} /> Vendedores
            </button>
            <div className="mono text-[11px] text-slate-500 flex items-center gap-1.5 h-5 w-16 justify-end">
              {saveState === "saving" && <><Loader2 size={12} className="animate-spin" /> salvando</>}
              {saveState === "saved" && <><Check size={12} className="text-[#4f9d69]" /> salvo</>}
            </div>
            <div className="relative">
              <div className="flex items-center gap-2 px-3 py-1.5 rounded-full" style={{ background: "#1c222c", border: "1px solid #2c3444" }}>
                <Search size={13} className="text-slate-500" />
                <input
                  value={buscaGlobal}
                  onChange={(e) => { setBuscaGlobal(e.target.value); setBuscaAberta(true); }}
                  onFocus={() => setBuscaAberta(true)}
                  placeholder="ir direto para uma cidade…"
                  className="bg-transparent text-sm text-slate-100 placeholder-slate-600 outline-none w-48"
                />
                {buscaGlobal && (
                  <button onClick={() => { setBuscaGlobal(""); setBuscaAberta(false); }}>
                    <X size={13} className="text-slate-500" />
                  </button>
                )}
              </div>
              {buscaAberta && resultadosBusca.length > 0 && (
                <div style={{ background: "#1c222c", border: "1px solid #2c3444" }} className="absolute right-0 mt-1.5 w-64 rounded-xl overflow-hidden shadow-2xl z-20">
                  {resultadosBusca.map((r) => (
                    <button
                      key={r.uf + r.nome}
                      onClick={() => irParaCidade(r.uf, r.nome)}
                      className="w-full text-left px-3.5 py-2 text-sm text-slate-200 hover:bg-[#252d3a] flex items-center justify-between"
                    >
                      <span>{r.nome}</span>
                      <span className="mono text-[10px] text-slate-500">{r.uf}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="px-5 py-5 sm:px-8 sm:py-7 max-w-7xl mx-auto">
        {tela === "segmentos" ? (
          <SegmentosOverview
            data={data}
            resumoPorSegmento={resumoPorSegmento}
            onEscolher={(seg) => { setSegmentoAtual(seg); setTela("mapa"); setUfSelecionado(null); setFiltro(""); }}
            novoSegmento={novoSegmento}
            setNovoSegmento={setNovoSegmento}
            mostraNovoSegmento={mostraNovoSegmento}
            setMostraNovoSegmento={setMostraNovoSegmento}
            addSegmento={addSegmento}
            removeSegmento={removeSegmento}
          />
        ) : tela === "geral" ? (
          <PainelGeralView
            data={data}
            resumoPorSegmento={resumoPorSegmento}
            resumoGlobal={resumoGlobal}
            onIrParaSegmento={(seg) => { setSegmentoAtual(seg); setTela("mapa"); setUfSelecionado(null); setFiltro(""); }}
            onExportar={exportarCSV}
            onVoltar={() => setTela("segmentos")}
            onSetMeta={setMeta}
          />
        ) : tela === "vendedores" ? (
          <VendedoresView
            data={data}
            resumoGlobal={resumoGlobal}
            onAdd={addVendedor}
            onRemove={removeVendedor}
            onDesatribuir={(seg, uf) => atribuirVendedor(seg, uf, null)}
            onAtribuir={(vendedor, seg, uf) => atribuirVendedor(seg, uf, vendedor)}
            onIrPara={(seg, uf) => { setSegmentoAtual(seg); setUfSelecionado(uf); setFiltro(""); setTela("mapa"); }}
            onVoltar={() => setTela("segmentos")}
          />
        ) : (
          <>
            <div className="flex flex-wrap items-center gap-2 mb-6">
              <button
                onClick={() => setTela("segmentos")}
                style={{ border: "1px solid #2c3444", color: "#8b95a6" }}
                className="px-3 py-1.5 rounded-full text-sm flex items-center gap-1"
              >
                <ChevronLeft size={13} /> segmentos
              </button>
              <span style={{ background: "#e0a458", color: "#14181f" }} className="px-3.5 py-1.5 rounded-full text-sm font-medium">
                {segmentoAtual}
              </span>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-5 gap-3 mb-7">
              {[
                { label: "estados com registro", value: resumoGeral.estados },
                { label: "cidades mapeadas", value: resumoGeral.cidades },
                { label: "empresas encontradas", value: resumoGeral.empresas.toLocaleString("pt-BR") },
                { label: "clientes fechados", value: resumoGeral.fechados.toLocaleString("pt-BR"), destaque: true },
                { label: "valor fechado", value: fmtBRL(resumoGeral.valor), destaque: true },
              ].map((it) => (
                <div key={it.label} style={{ background: "#1c222c", border: "1px solid " + (it.destaque ? "#3a6b4c" : "#232a36") }} className="rounded-xl px-4 py-3">
                  <div className="mono text-xl sm:text-2xl font-bold" style={{ color: it.destaque ? "#4f9d69" : "#f8fafc" }}>{it.value}</div>
                  <div className="text-[11px] text-slate-500 mt-0.5">{it.label}</div>
                </div>
              ))}
            </div>

            {!ufSelecionado ? (
              <div>
                <div className="flex items-center justify-between mb-3">
                  <div className="text-[11px] mono tracking-widest text-slate-500 uppercase">
                    {segmentoAtual} — clique num estado no mapa
                  </div>
                  <div className="flex items-center gap-3 text-[11px] text-slate-500">
                    <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-sm inline-block" style={{ background: "#232a36" }} /> sem registro</span>
                    <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-sm inline-block" style={{ background: "#8a6a34" }} /> em andamento</span>
                    <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-sm inline-block" style={{ background: "#3a6b4c" }} /> concluído</span>
                  </div>
                </div>
                <div style={{ background: "#191d25", border: "1px solid #232a36" }} className="rounded-2xl p-4 sm:p-6 relative">
                  {hoveredUf && (
                    <div className="absolute top-4 left-4 mono text-xs text-slate-300 flex items-center gap-2 z-10">
                      <MapPin size={12} className="text-[#e0a458]" />
                      {STATES_GEO.states[hoveredUf].name}
                      {resumoPorEstado[hoveredUf] && (
                        <span className="text-slate-500">
                          · {resumoPorEstado[hoveredUf].total} cidade{resumoPorEstado[hoveredUf].total === 1 ? "" : "s"} mapeada{resumoPorEstado[hoveredUf].total === 1 ? "" : "s"}
                        </span>
                      )}
                      {data.atribuicoes[chaveAtrib(segmentoAtual, hoveredUf)] && (
                        <span className="flex items-center gap-1 text-[#e0a458]">
                          <Users size={11} /> {data.atribuicoes[chaveAtrib(segmentoAtual, hoveredUf)]}
                        </span>
                      )}
                    </div>
                  )}
                  <svg viewBox={STATES_GEO.viewBox.join(" ")} className="w-full h-auto" style={{ maxHeight: 560, display: "block", margin: "0 auto" }}>
                    {Object.entries(STATES_GEO.states).map(([uf, s]) => (
                      <path
                        key={uf}
                        d={s.path}
                        fill={estadoCor(uf)}
                        stroke={hoveredUf === uf ? "#e0a458" : "#0d1016"}
                        strokeWidth={hoveredUf === uf ? 0.22 : 0.1}
                        onMouseEnter={() => setHoveredUf(uf)}
                        onMouseLeave={() => setHoveredUf(null)}
                        onClick={() => { setUfSelecionado(uf); setFiltro(""); }}
                        style={{ cursor: "pointer", transition: "fill .12s" }}
                      />
                    ))}
                  </svg>
                </div>
              </div>
            ) : (
              <EstadoView
                uf={ufSelecionado}
                segmentoAtual={segmentoAtual}
                data={data}
                updateCidade={updateCidade}
                filtro={filtro}
                setFiltro={setFiltro}
                sortBy={sortBy}
                setSortBy={setSortBy}
                onVoltar={() => { setUfSelecionado(null); setFiltro(""); }}
                resumo={resumoPorEstado[ufSelecionado]}
                vendedores={data.vendedores}
                vendedorAtual={data.atribuicoes[chaveAtrib(segmentoAtual, ufSelecionado)] || ""}
                onAtribuirVendedor={(v) => atribuirVendedor(segmentoAtual, ufSelecionado, v)}
                mensagem={data.mensagens?.[segmentoAtual] || MENSAGEM_PADRAO_CONTABILIDADE}
                onChangeMensagem={(txt) => updateMensagem(segmentoAtual, txt)}
              />
            )}
          </>
        )}
      </div>
    </div>
  );
}

const FORMATO_STYLE = {
  "Site institucional": { color: "#e0a458", bg: "#2a2418", short: "Site" },
  "Instagram + Google": { color: "#c792ea", bg: "#2a2333", short: "Insta+Google" },
  "Google Perfil da Empresa": { color: "#7aa2c9", bg: "#1e2733", short: "Google Perfil" },
};

function SegmentosOverview({ data, resumoPorSegmento, onEscolher, novoSegmento, setNovoSegmento, mostraNovoSegmento, setMostraNovoSegmento, addSegmento, removeSegmento }) {
  const [busca, setBusca] = useState("");
  const ordenados = useMemo(() => {
    const lista = data.ordemSegmentos.filter((s) => s.toLowerCase().includes(busca.toLowerCase()));
    return lista.sort((a, b) => (resumoPorSegmento[b]?.cidades || 0) - (resumoPorSegmento[a]?.cidades || 0));
  }, [data.ordemSegmentos, resumoPorSegmento, busca]);

  return (
    <div>
      <div className="text-[11px] mono tracking-widest text-slate-500 uppercase mb-1">
        {data.ordemSegmentos.length} segmentos
      </div>
      <h2 className="text-lg font-semibold text-slate-50 mb-4">Qual segmento você vai prospectar?</h2>

      <div className="flex flex-wrap items-center gap-2 mb-4">
        <div className="flex items-center gap-2 px-3 py-2 rounded-lg flex-1 min-w-[200px]" style={{ background: "#1c222c", border: "1px solid #2c3444" }}>
          <Search size={14} className="text-slate-500" />
          <input
            value={busca}
            onChange={(e) => setBusca(e.target.value)}
            placeholder="filtrar segmento…"
            className="bg-transparent text-sm text-slate-100 placeholder-slate-600 outline-none w-full"
          />
          {busca && <button onClick={() => setBusca("")}><X size={13} className="text-slate-500" /></button>}
        </div>
        {mostraNovoSegmento ? (
          <div className="flex items-center gap-1.5">
            <input
              autoFocus
              value={novoSegmento}
              onChange={(e) => setNovoSegmento(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && addSegmento()}
              placeholder="nome do segmento"
              style={{ background: "#1c222c", border: "1px solid #2c3444" }}
              className="px-3 py-2 rounded-lg text-sm text-slate-100 placeholder-slate-500 w-48"
            />
            <button onClick={addSegmento} style={{ background: "#e0a458" }} className="w-9 h-9 rounded-lg flex items-center justify-center text-[#14181f]">
              <Check size={15} />
            </button>
          </div>
        ) : (
          <button
            onClick={() => setMostraNovoSegmento(true)}
            style={{ border: "1px dashed #3a4252", color: "#8b95a6" }}
            className="px-3 py-2 rounded-lg text-sm flex items-center gap-1.5"
          >
            <Plus size={14} /> segmento próprio
          </button>
        )}
      </div>

      <div className="flex items-center gap-3 mb-3 text-[10px]">
        {Object.entries(FORMATO_STYLE).map(([k, v]) => (
          <span key={k} className="flex items-center gap-1.5 text-slate-500">
            <span className="w-2 h-2 rounded-full inline-block" style={{ background: v.color }} /> {k}
          </span>
        ))}
      </div>

      <div className="hidden sm:flex items-center gap-3 px-4 py-1.5 text-[10px] uppercase tracking-wider text-slate-600">
        <span className="flex-1">Segmento</span>
        <span className="w-14 text-right">% sem site</span>
        <span className="w-28 text-right">Formato ideal</span>
        <span className="w-14 text-right">Cidades</span>
        <span className="w-16 text-right">Empresas</span>
        <span className="w-14 text-right">Fechados</span>
        <span className="w-4" />
      </div>

      <div className="rounded-xl overflow-hidden" style={{ border: "1px solid #232a36" }}>
        {ordenados.map((seg, i) => {
          const r = resumoPorSegmento[seg] || { cidades: 0, concluidas: 0, andamento: 0, empresas: 0, fechados: 0, estadosComReg: 0 };
          const semProspeccao = r.cidades === 0;
          const info = CURATED_INFO_BY_NAME[seg];
          const formato = info ? FORMATO_STYLE[info.f] : null;
          return (
            <div
              key={seg}
              onClick={() => onEscolher(seg)}
              className="group flex items-center gap-3 px-4 py-2.5 cursor-pointer transition-colors"
              style={{
                background: i % 2 === 0 ? "#191d25" : "#1c222c",
                borderTop: i === 0 ? "none" : "1px solid #20262f",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = "#232a36")}
              onMouseLeave={(e) => (e.currentTarget.style.background = i % 2 === 0 ? "#191d25" : "#1c222c")}
            >
              <span className="flex-1 text-sm text-slate-100 truncate">{seg}</span>
              <span className="mono text-xs text-slate-400 w-14 text-right shrink-0">{info ? `~${info.p}%` : "—"}</span>
              <span className="w-28 text-right shrink-0 hidden sm:block">
                {formato && (
                  <span
                    className="text-[10px] px-2 py-0.5 rounded-full font-medium"
                    style={{ background: formato.bg, color: formato.color }}
                  >
                    {formato.short}
                  </span>
                )}
              </span>
              {semProspeccao ? (
                <span className="text-[10px] text-slate-600 italic mr-2 hidden lg:inline">sem prospecção</span>
              ) : (
                <>
                  <span className="mono text-xs text-slate-300 w-14 text-right shrink-0">{r.cidades}</span>
                  <span className="mono text-xs text-[#e0a458] w-16 text-right shrink-0">{r.empresas}</span>
                  <span className="mono text-xs text-[#4f9d69] w-14 text-right font-semibold shrink-0">{r.fechados}</span>
                </>
              )}
              <button
                onClick={(e) => { e.stopPropagation(); removeSegmento(seg); }}
                title={`Remover ${seg}`}
                className="hidden group-hover:flex items-center justify-center w-6 h-6 rounded-full bg-[#3a1e1e] text-[#e08a8a] shrink-0"
              >
                <Trash2 size={11} />
              </button>
              <ChevronRight size={15} className="text-slate-600 shrink-0" />
            </div>
          );
        })}
        {ordenados.length === 0 && (
          <div className="text-center text-slate-500 text-sm py-10">Nenhum segmento encontrado para "{busca}".</div>
        )}
      </div>
    </div>
  );
}

function EstadoView({ uf, segmentoAtual, data, updateCidade, filtro, setFiltro, sortBy, setSortBy, onVoltar, resumo, vendedores, vendedorAtual, onAtribuirVendedor, mensagem, onChangeMensagem }) {
  const s = STATES_GEO.states[uf];
  const [x, y, w, h] = s.bbox;
  const pad = Math.max(w, h) * 0.1;
  const tracked = data.segmentos?.[segmentoAtual]?.[uf] || {};
  const listaCompleta = MUNICIPIOS_BY_UF[uf] || [];
  const rowRefs = useRef({});
  const mapRef = useRef(null);
  const [hoverCidade, setHoverCidade] = useState(null);
  const [modo, setModo] = useState("tabela");
  const [verBairros, setVerBairros] = useState(false);
  const [cidadeContatos, setCidadeContatos] = useState(null);
  const [mostraMensagem, setMostraMensagem] = useState(false);
  const [verMapaMobile, setVerMapaMobile] = useState(false);
  const maxPop = listaCompleta.length ? listaCompleta[0].p || 1 : 1;

  // Sempre usa o contorno completo do estado (o "zoom" no cluster de cidades
  // cortava o mapa e só sobrava um fragmento torto do contorno).
  const vb = [x - pad, y - pad, w + 2 * pad, h + 2 * pad].join(" ");
  const mapScale = Math.max(w, h);

  const fonteLista = uf === "SP" && verBairros ? SP_CAPITAL_DISTRITOS : listaCompleta;


  const rows = useMemo(() => {
    let r = fonteLista
      .filter((c) => c.n.toLowerCase().includes(filtro.toLowerCase()))
      .map((c) => ({ nome: c.n, cap: c.cap || false, lat: c.lat, lon: c.lon, pop: c.p, ...(tracked[c.n] || defaultCidade()) }));
    if (sortBy === "empresas") r = r.sort((a, b) => numOrZero(b.empresas) - numOrZero(a.empresas));
    else if (sortBy === "fechados") r = r.sort((a, b) => numOrZero(b.fechados) - numOrZero(a.fechados));
    else if (sortBy === "status") r = r.sort((a, b) => STATUS_ORDER[a.status] - STATUS_ORDER[b.status]);
    else if (sortBy === "nome") r = r.sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"));
    else r = r.sort((a, b) => (b.pop || 0) - (a.pop || 0));
    return r;
  }, [fonteLista, filtro, sortBy, tracked]);

  const clicaPonto = (nome) => {
    setFiltro(nome);
    setTimeout(() => {
      rowRefs.current[nome]?.scrollIntoView({ block: "center", behavior: "smooth" });
    }, 50);
  };

  const dotColor = (nome) => {
    const info = tracked[nome];
    const status = info?.status || "nao_iniciado";
    return STATUS_OPTS.find((o) => o.v === status)?.color;
  };

  const dotRadius = (c) => {
    if (c.cap) return mapScale * 0.045;
    const pr = Math.sqrt((c.p || 0) / maxPop);
    return mapScale * (0.012 + pr * 0.026);
  };

  const STATUS_ORDEM = STATUS_OPTS.map((o) => o.v);
  const mover = (nome, atual, direcao) => {
    const idx = STATUS_ORDEM.indexOf(atual);
    const novoIdx = idx + direcao;
    if (novoIdx < 0 || novoIdx > STATUS_ORDEM.length - 1) return;
    updateCidade(uf, nome, { status: STATUS_ORDEM[novoIdx] });
  };
  const cidadesTrabalhadas = useMemo(() => rows.filter((r) => tracked[r.nome]), [rows, tracked]);

  const entrarCidade = (c, e) => {
    const rect = mapRef.current.getBoundingClientRect();
    setHoverCidade({
      nome: c.n,
      pop: c.p,
      cap: c.cap,
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
      ...(tracked[c.n] || defaultCidade()),
    });
  };

  return (
    <div>
      <button onClick={onVoltar} className="flex items-center gap-1 text-sm text-slate-400 hover:text-slate-200 mb-4">
        <ChevronLeft size={15} /> voltar ao mapa do Brasil
      </button>

      <div className="flex items-center gap-2 mb-1 flex-wrap">
        <MapPin size={16} className="text-[#e0a458]" />
        <h2 className="text-lg font-semibold text-slate-50">{s.name}</h2>
        <span className="mono text-xs text-slate-500">· {segmentoAtual}</span>
        {CURATED_INFO_BY_NAME[segmentoAtual] && (
          <>
            <span className="mono text-xs text-slate-500">· ~{CURATED_INFO_BY_NAME[segmentoAtual].p}% sem site</span>
            <span
              className="text-[10px] px-2 py-0.5 rounded-full font-medium"
              style={{
                background: FORMATO_STYLE[CURATED_INFO_BY_NAME[segmentoAtual].f]?.bg,
                color: FORMATO_STYLE[CURATED_INFO_BY_NAME[segmentoAtual].f]?.color,
              }}
            >
              {FORMATO_STYLE[CURATED_INFO_BY_NAME[segmentoAtual].f]?.short}
            </span>
          </>
        )}
        {resumo && (
          <span className="mono text-xs text-slate-500">
            · {resumo.total} de {listaCompleta.length} cidades · {resumo.empresas.toLocaleString("pt-BR")} empresas · <span className="text-[#4f9d69]">{resumo.fechados.toLocaleString("pt-BR")} fechados</span> · <span className="text-[#4f9d69]">{fmtBRL(resumo.valor)}</span>
          </span>
        )}
      </div>
      <div className="flex items-center gap-3 flex-wrap text-[11px] text-slate-500 mb-2">
        {STATUS_OPTS.map((o) => (
          <span key={o.v} className="flex items-center gap-1.5">
            <span className="w-2.5 h-2.5 rounded-full inline-block" style={{ background: o.color }} /> {o.label}
          </span>
        ))}
        <button
          onClick={() => setMostraMensagem((v) => !v)}
          style={{ background: "#1c222c", border: "1px solid #2c3444", color: "#c3cad6" }}
          className="text-[11px] px-2.5 py-1 rounded-lg"
        >
          mensagem-padrão do segmento {mostraMensagem ? "▲" : "▼"}
        </button>
        <span className="flex items-center gap-1.5 ml-auto">
          <Users size={13} className="text-slate-500" />
          <select
            value={vendedorAtual}
            onChange={(e) => onAtribuirVendedor(e.target.value || null)}
            style={{
              background: vendedorAtual ? "#2a2418" : "#14181f",
              border: "1px solid " + (vendedorAtual ? "#e0a458" : "#2c3444"),
              color: vendedorAtual ? "#e0a458" : "#8b95a6",
            }}
            className="text-xs rounded-lg px-2 py-1.5"
          >
            <option value="">sem vendedor atribuído</option>
            {vendedores.map((v) => (
              <option key={v} value={v}>{v}</option>
            ))}
          </select>
        </span>
      </div>

      {mostraMensagem && (
        <div style={{ background: "#191d25", border: "1px solid #232a36" }} className="rounded-2xl p-3 mb-4">
          <div className="text-[11px] text-slate-500 mb-1.5">
            Mensagem usada nos links de WhatsApp deste segmento. Use <span className="mono text-slate-300">{"{nome}"}</span>, <span className="mono text-slate-300">{"{cidade}"}</span> e <span className="mono text-slate-300">{"{vendedor}"}</span> para personalizar — o vendedor de cada cidade você define dentro do botão "Contatos" daquela cidade.
          </div>
          <textarea
            value={mensagem}
            onChange={(e) => onChangeMensagem(e.target.value)}
            placeholder="Oi {nome}, tudo bem? Vi que sua empresa em {cidade} ainda não tem site..."
            rows={3}
            style={{ background: "#14181f", border: "1px solid #2c3444" }}
            className="w-full px-3 py-2 rounded-lg text-slate-200 placeholder-slate-600 text-sm"
          />
        </div>
      )}

      <button
        onClick={() => setVerMapaMobile((v) => !v)}
        style={{ background: "#1c222c", border: "1px solid #2c3444", color: "#c3cad6" }}
        className="lg:hidden w-full flex items-center justify-center gap-2 mb-3 py-2.5 rounded-xl text-sm font-medium"
      >
        <MapPin size={14} /> {verMapaMobile ? "Ver lista de cidades" : "Ver mapa"}
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-[400px_1fr] gap-5">
        <div style={{ background: "#191d25", border: "1px solid #232a36" }} className={(verMapaMobile ? "block" : "hidden") + " lg:block rounded-2xl p-4 relative"} ref={mapRef}>
          <svg viewBox={vb} className="w-full h-auto" style={{ maxHeight: 460 }}>
            <path d={s.path} fill="#20262f" stroke="#3d4658" strokeWidth={mapScale * 0.006} />
            {listaCompleta.map((c) => {
              const info = tracked[c.n];
              const fechados = numOrZero(info?.fechados);
              const r = dotRadius(c);
              return (
                <g key={c.n}>
                  {fechados > 0 && (
                    <circle cx={c.lon} cy={-c.lat} r={r * 2.2} fill="#4f9d69" opacity={0.22} style={{ pointerEvents: "none" }} />
                  )}
                  <circle
                    cx={c.lon}
                    cy={-c.lat}
                    r={r}
                    fill={dotColor(c.n)}
                    stroke={c.cap ? "#f3f3f3" : "#0d1016"}
                    strokeWidth={c.cap ? mapScale * 0.003 : mapScale * 0.0015}
                    onClick={() => clicaPonto(c.n)}
                    onMouseEnter={(e) => entrarCidade(c, e)}
                    onMouseLeave={() => setHoverCidade(null)}
                    style={{ cursor: "pointer" }}
                  />
                </g>
              );
            })}
          </svg>
          {hoverCidade && (
            <div
              className="absolute z-20 pointer-events-none"
              style={{
                left: Math.min(Math.max(hoverCidade.x, 90), (mapRef.current?.clientWidth || 300) - 90),
                top: Math.max(hoverCidade.y - 14, 8),
                transform: "translate(-50%, -100%)",
              }}
            >
              <div style={{ background: "#20262f", border: "1px solid #3a4252" }} className="rounded-lg px-3 py-2 text-xs shadow-2xl whitespace-nowrap">
                <div className="text-slate-100 font-semibold flex items-center gap-1">
                  {hoverCidade.cap && <Star size={9} className="text-[#e0a458]" />}
                  {hoverCidade.nome}
                </div>
                {hoverCidade.pop ? <div className="text-slate-500 text-[10px] mb-1">{fmtPop(hoverCidade.pop)}</div> : null}
                <div className="flex items-center gap-2 mt-1">
                  <span style={{ color: STATUS_OPTS.find((o) => o.v === hoverCidade.status)?.color }} className="flex items-center gap-1">
                    <span className="w-1.5 h-1.5 rounded-full inline-block" style={{ background: STATUS_OPTS.find((o) => o.v === hoverCidade.status)?.color }} />
                    {STATUS_OPTS.find((o) => o.v === hoverCidade.status)?.label}
                  </span>
                </div>
                <div className="flex items-center gap-3 mt-1 mono">
                  <span className="text-slate-400">{numOrZero(hoverCidade.empresas)} empresas</span>
                  <span className="text-[#4f9d69] font-bold">{numOrZero(hoverCidade.fechados)} fechados</span>
                  {numOrZero(hoverCidade.valor) > 0 && <span className="text-[#e0a458] font-bold">{fmtBRL(hoverCidade.valor)}</span>}
                </div>
              </div>
            </div>
          )}
          <div className="text-[10px] text-slate-500 flex items-center gap-1 mt-2">
            <Star size={9} className="text-slate-300" /> capital · ponto maior = cidade mais populosa · brilho verde = já fechou cliente
          </div>
        </div>

        <div style={{ background: "#191d25", border: "1px solid #232a36" }} className={(verMapaMobile ? "hidden" : "block") + " lg:block rounded-2xl p-4 flex flex-col"}>
          {MERCADO_REAL[segmentoAtual]?.[uf] && (
            <div className="text-[11px] text-slate-500 mb-3 flex items-center gap-1.5">
              <span className="text-[10px] px-1.5 py-0.5 rounded" style={{ background: "#1e2733", color: "#7aa2c9" }}>mercado</span>
              = quantidade real de empresas ativas (Receita Federal, via Econodata, jul/2026) — piloto só neste segmento, nestas cidades.
            </div>
          )}
          {uf === "SP" && (
            <div className="flex items-center justify-between mb-3 px-3 py-2 rounded-lg" style={{ background: "#1c222c", border: "1px solid #2c3444" }}>
              <span className="text-xs text-slate-300">
                {verBairros ? "Vendo os 96 bairros da capital" : "São Paulo (capital) conta como 1 linha aqui — dá pra abrir os 96 bairros"}
              </span>
              <button
                onClick={() => { setVerBairros(!verBairros); setFiltro(""); }}
                style={{ background: verBairros ? "#2a2418" : "#e0a458", color: verBairros ? "#e0a458" : "#14181f" }}
                className="px-3 py-1.5 rounded-lg text-xs font-semibold flex items-center gap-1.5 shrink-0"
              >
                {verBairros ? <><ChevronLeft size={12} /> voltar pras cidades</> : <>ver bairros (96) <ChevronRight size={12} /></>}
              </button>
            </div>
          )}
          <div className="flex flex-wrap items-center gap-2 mb-3">
            <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg flex-1 min-w-[160px]" style={{ background: "#14181f", border: "1px solid #2c3444" }}>
              <Search size={13} className="text-slate-500" />
              <input
                value={filtro}
                onChange={(e) => setFiltro(e.target.value)}
                placeholder={verBairros ? "filtrar bairro…" : "filtrar cidade…"}
                className="bg-transparent text-sm text-slate-100 placeholder-slate-600 outline-none w-full"
              />
              {filtro && <button onClick={() => setFiltro("")}><X size={13} className="text-slate-500" /></button>}
            </div>
            <select
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
              style={{ background: "#14181f", border: "1px solid #2c3444" }}
              className="text-xs text-slate-300 rounded-lg px-2 py-2"
            >
              <option value="populacao">ordenar: mais habitantes</option>
              <option value="nome">ordenar: nome (A-Z)</option>
              <option value="empresas">ordenar: nº de empresas</option>
              <option value="fechados">ordenar: nº de fechados</option>
              <option value="status">ordenar: status</option>
            </select>
            <div className="hidden lg:flex items-center gap-1 rounded-lg p-0.5" style={{ background: "#14181f", border: "1px solid #2c3444" }}>
              {[{ v: "tabela", l: "Tabela" }, { v: "kanban", l: "Kanban" }].map((o) => (
                <button
                  key={o.v}
                  onClick={() => setModo(o.v)}
                  style={{ background: modo === o.v ? "#e0a458" : "transparent", color: modo === o.v ? "#14181f" : "#8b95a6" }}
                  className="px-2.5 py-1.5 rounded-md text-xs font-medium"
                >
                  {o.l}
                </button>
              ))}
            </div>
          </div>

          <div className="hidden lg:block">
          {modo === "kanban" ? (
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3" style={{ maxHeight: 500, overflowY: "auto" }}>
              {STATUS_OPTS.map((opt, colIdx) => {
                const cidadesCol = cidadesTrabalhadas.filter((r) => r.status === opt.v);
                return (
                  <div key={opt.v} className="rounded-xl p-2.5" style={{ background: "#14181f", border: "1px solid #232a36" }}>
                    <div className="flex items-center gap-1.5 px-1.5 py-1 mb-2">
                      <span className="w-2 h-2 rounded-full inline-block" style={{ background: opt.color }} />
                      <span className="text-xs font-semibold text-slate-300">{opt.label}</span>
                      <span className="mono text-[10px] text-slate-500 ml-auto">{cidadesCol.length}</span>
                    </div>
                    <div className="flex flex-col gap-2">
                      {cidadesCol.length === 0 && (
                        <div className="text-[11px] text-slate-600 italic px-1.5 py-3 text-center">vazio</div>
                      )}
                      {cidadesCol.map((r) => (
                        <div key={r.nome} className="rounded-lg p-2.5" style={{ background: "#1c222c", border: "1px solid #232a36" }}>
                          <div className="flex items-center gap-1.5 mb-1.5">
                            {r.cap && <Star size={9} className="text-slate-300 shrink-0" />}
                            <span className="text-sm text-slate-100 font-medium truncate">{r.nome}</span>
                            {(r.contatos || []).length > 0 && (
                              <span className="mono text-[10px] px-1.5 py-0.5 rounded shrink-0" style={{ background: "#1c2a22", color: "#4f9d69" }}>
                                {(r.contatos || []).length}
                              </span>
                            )}
                          </div>
                          <div className="flex items-center gap-2 mono text-[10px] mb-2 flex-wrap">
                            <span className="text-slate-500">{numOrZero(r.empresas)} emp.</span>
                            <span className="text-[#4f9d69] font-semibold">{numOrZero(r.fechados)} fech.</span>
                            {numOrZero(r.valor) > 0 && <span className="text-[#e0a458]">{fmtBRL(r.valor)}</span>}
                          </div>
                          <div className="flex items-center gap-1.5">
                            <button
                              onClick={() => mover(r.nome, r.status, -1)}
                              disabled={colIdx === 0}
                              style={{ opacity: colIdx === 0 ? 0.3 : 1 }}
                              className="text-[10px] px-2 py-1 rounded-md flex items-center gap-0.5 text-slate-400 hover:bg-[#20262f]"
                            >
                              <ChevronLeft size={10} /> voltar
                            </button>
                            <button
                              onClick={() => mover(r.nome, r.status, 1)}
                              disabled={colIdx === STATUS_OPTS.length - 1}
                              style={{ opacity: colIdx === STATUS_OPTS.length - 1 ? 0.3 : 1, background: "#20262f" }}
                              className="text-[10px] px-2 py-1 rounded-md flex items-center gap-0.5 text-slate-200 ml-auto"
                            >
                              avançar <ChevronRight size={10} />
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
          <div className="overflow-y-auto rounded-lg" style={{ maxHeight: 500, border: "1px solid #232a36" }}>
            <table className="w-full text-sm">
              <thead className="sticky top-0 z-10" style={{ background: "#20262f" }}>
                <tr className="text-[10px] uppercase tracking-wider text-slate-500">
                  <th className="text-left px-3 py-2 font-medium">Cidade</th>
                  <th className="text-left px-2 py-2 font-medium w-20">Empresas</th>
                  <th className="text-left px-2 py-2 font-medium w-20">Fechados</th>
                  <th className="text-left px-2 py-2 font-medium w-24">Valor (R$)</th>
                  <th className="text-left px-2 py-2 font-medium w-28">Status</th>
                  <th className="text-left px-3 py-2 font-medium">Obs.</th>
                  <th className="text-left px-2 py-2 font-medium w-32">Contatos (WhatsApp)</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((r) => (
                  <tr
                    key={r.nome}
                    ref={(el) => (rowRefs.current[r.nome] = el)}
                    style={{ borderTop: "1px solid #20262f", background: tracked[r.nome] ? "#1c222c" : "transparent" }}
                  >
                    <td className="px-3 py-1.5 text-slate-200 whitespace-nowrap">
                      <span className="flex items-center gap-1.5">
                        {r.cap && <Star size={10} className="text-slate-300 shrink-0" />}
                        <span>
                          {r.nome}
                          {(r.contatos || []).length > 0 && (
                            <span className="mono text-[10px] ml-1.5 px-1.5 py-0.5 rounded" style={{ background: "#1c2a22", color: "#4f9d69" }}>
                              {(r.contatos || []).length} contato{(r.contatos || []).length === 1 ? "" : "s"}
                            </span>
                          )}
                          {r.pop ? <span className="text-slate-500 text-[10px] ml-1.5">{fmtPop(r.pop)}</span> : null}
                          {r.vendedor && (
                            <span className="text-[10px] ml-1.5 px-1.5 py-0.5 rounded" style={{ background: "#2a2418", color: "#e0a458" }}>
                              {r.vendedor}
                            </span>
                          )}
                          {MERCADO_REAL[segmentoAtual]?.[uf]?.[r.nome] != null && (
                            <span
                              title="Empresas ativas no CNAE de contabilidade nesta cidade — dados abertos da Receita Federal, via Econodata (jul/2026)"
                              className="text-[10px] ml-1.5 px-1.5 py-0.5 rounded"
                              style={{ background: "#1e2733", color: "#7aa2c9" }}
                            >
                              {MERCADO_REAL[segmentoAtual][uf][r.nome].toLocaleString("pt-BR")} no mercado
                            </span>
                          )}
                        </span>
                      </span>
                    </td>
                    <td className="px-2 py-1.5">
                      <input
                        value={r.empresas}
                        onChange={(e) => updateCidade(uf, r.nome, { empresas: e.target.value.replace(/[^0-9]/g, "") })}
                        placeholder="0"
                        inputMode="numeric"
                        title="Quantas empresas você encontrou/vai contatar nesta cidade"
                        style={{ background: "#14181f", border: "1px solid #2c3444" }}
                        className="mono w-16 px-2 py-1 rounded text-slate-100 text-center text-xs"
                      />
                    </td>
                    <td className="px-2 py-1.5">
                      <input
                        value={r.fechados}
                        onChange={(e) => updateCidade(uf, r.nome, { fechados: e.target.value.replace(/[^0-9]/g, "") })}
                        placeholder="0"
                        inputMode="numeric"
                        title="Quantos clientes você fechou nesta cidade"
                        style={{
                          background: numOrZero(r.fechados) > 0 ? "#1c2a22" : "#14181f",
                          border: "1px solid " + (numOrZero(r.fechados) > 0 ? "#4f9d69" : "#2c3444"),
                          color: numOrZero(r.fechados) > 0 ? "#4f9d69" : "#e5e9ef",
                        }}
                        className="mono w-16 px-2 py-1 rounded text-center text-xs font-bold"
                      />
                    </td>
                    <td className="px-2 py-1.5">
                      <input
                        value={r.valor}
                        onChange={(e) => updateCidade(uf, r.nome, { valor: e.target.value.replace(/[^0-9]/g, "") })}
                        placeholder="0"
                        inputMode="numeric"
                        title="Valor total fechado nesta cidade (R$)"
                        style={{ background: "#14181f", border: "1px solid #2c3444" }}
                        className="mono w-20 px-2 py-1 rounded text-[#e0a458] text-center text-xs"
                      />
                    </td>
                    <td className="px-2 py-1.5">
                      <div className="flex items-center gap-1">
                        {STATUS_OPTS.map((opt) => (
                          <button
                            key={opt.v}
                            title={opt.label}
                            onClick={() => updateCidade(uf, r.nome, { status: opt.v })}
                            style={{
                              background: r.status === opt.v ? opt.color : "transparent",
                              border: `1px solid ${r.status === opt.v ? opt.color : "#2c3444"}`,
                              color: r.status === opt.v ? "#14181f" : "#8b95a6",
                            }}
                            className="w-6 h-6 rounded-full flex items-center justify-center shrink-0"
                          >
                            <StatusIcon status={opt.v} size={10} />
                          </button>
                        ))}
                      </div>
                    </td>
                    <td className="px-3 py-1.5">
                      <input
                        value={r.obs}
                        onChange={(e) => updateCidade(uf, r.nome, { obs: e.target.value })}
                        placeholder="—"
                        style={{ background: "#14181f", border: "1px solid #2c3444" }}
                        className="w-full px-2 py-1 rounded text-slate-300 placeholder-slate-600 text-xs"
                      />
                    </td>
                    <td className="px-2 py-1.5">
                      {(() => {
                        const contatos = r.contatos || [];
                        const enviados = contatos.filter((c) => c.enviado).length;
                        return (
                          <button
                            onClick={() => setCidadeContatos(r.nome)}
                            style={{
                              background: contatos.length ? "#1c2a22" : "#14181f",
                              border: "1px solid " + (contatos.length ? "#4f9d69" : "#2c3444"),
                              color: contatos.length ? "#4f9d69" : "#8b95a6",
                            }}
                            className="text-[11px] px-2.5 py-1.5 rounded-lg font-medium whitespace-nowrap"
                          >
                            {contatos.length ? `${enviados}/${contatos.length} enviados` : "+ contatos"}
                          </button>
                        );
                      })()}
                    </td>
                  </tr>
                ))}
                {rows.length === 0 && (
                  <tr><td colSpan={7} className="text-center text-slate-500 text-sm py-8">Nenhum{verBairros ? " bairro" : "a cidade"} encontrad{verBairros ? "o" : "a"} para "{filtro}".</td></tr>
                )}
              </tbody>
            </table>
          </div>
          )}
          </div>

          <div className="lg:hidden flex flex-col gap-2" style={{ maxHeight: 560, overflowY: "auto" }}>
            {rows.length === 0 && (
              <div className="text-center text-slate-500 text-sm py-8">Nenhum{verBairros ? " bairro" : "a cidade"} encontrad{verBairros ? "o" : "a"} para "{filtro}".</div>
            )}
            {rows.map((r) => {
              const contatos = r.contatos || [];
              const enviados = contatos.filter((c) => c.enviado).length;
              return (
                <div
                  key={r.nome}
                  style={{ background: tracked[r.nome] ? "#1c222c" : "#191d25", border: "1px solid #232a36" }}
                  className="rounded-xl p-3.5 flex items-center gap-3"
                >
                  <button
                    onClick={() => {
                      const idx = STATUS_OPTS.findIndex((o) => o.v === r.status);
                      const next = STATUS_OPTS[(idx + 1) % STATUS_OPTS.length];
                      updateCidade(uf, r.nome, { status: next.v });
                    }}
                    title="Toca pra mudar o status"
                    style={{ background: STATUS_OPTS.find((o) => o.v === r.status)?.color }}
                    className="w-10 h-10 rounded-full flex items-center justify-center shrink-0"
                  >
                    <StatusIcon status={r.status} size={16} />
                  </button>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm text-slate-100 font-medium flex items-center gap-1.5 truncate">
                      {r.cap && <Star size={11} className="text-slate-300 shrink-0" />}
                      {r.nome}
                      {(r.contatos || []).length > 0 && (
                        <span className="mono text-[10px] px-1.5 py-0.5 rounded shrink-0" style={{ background: "#1c2a22", color: "#4f9d69" }}>
                          {(r.contatos || []).length}
                        </span>
                      )}
                    </div>
                    <div className="text-[11px] text-slate-500 mt-0.5 flex items-center gap-2 flex-wrap">
                      {r.pop ? <span>{fmtPop(r.pop)}</span> : null}
                      {numOrZero(r.fechados) > 0 && <span className="text-[#4f9d69] font-semibold">{r.fechados} fechado(s)</span>}
                      {r.vendedor && <span className="text-[#e0a458]">{r.vendedor}</span>}
                    </div>
                  </div>
                  <button
                    onClick={() => setCidadeContatos(r.nome)}
                    style={{
                      background: contatos.length ? "#1c2a22" : "#14181f",
                      border: "1px solid " + (contatos.length ? "#4f9d69" : "#2c3444"),
                      color: contatos.length ? "#4f9d69" : "#c3cad6",
                    }}
                    className="shrink-0 text-xs font-semibold px-3.5 py-2.5 rounded-xl whitespace-nowrap"
                  >
                    {contatos.length ? `${enviados}/${contatos.length}` : "Contatos"}
                  </button>
                </div>
              );
            })}
          </div>
        </div>
      </div>
      {cidadeContatos && (
        <ContatosModal
          cidade={cidadeContatos}
          uf={uf}
          segmentoAtual={segmentoAtual}
          mensagem={mensagem}
          contatos={(tracked[cidadeContatos] || defaultCidade()).contatos || []}
          vendedores={vendedores}
          vendedorCidade={(tracked[cidadeContatos] || defaultCidade()).vendedor || ""}
          onChangeVendedor={(v) => updateCidade(uf, cidadeContatos, { vendedor: v })}
          onFechar={() => setCidadeContatos(null)}
          onSalvar={(novosContatos) => updateCidade(uf, cidadeContatos, { contatos: novosContatos })}
        />
      )}
    </div>
  );
}

function ContatosModal({ cidade, uf, segmentoAtual, mensagem, contatos, vendedores, vendedorCidade, onChangeVendedor, onFechar, onSalvar }) {
  const [texto, setTexto] = useState("");

  const importar = () => {
    const novos = parseContatosTexto(texto);
    if (!novos.length) return;
    // evita duplicar por telefone
    const existentesTel = new Set(contatos.map((c) => c.telefone.replace(/\D/g, "")));
    const filtrados = novos.filter((n) => !existentesTel.has(n.telefone.replace(/\D/g, "")));
    onSalvar([...contatos, ...filtrados]);
    setTexto("");
  };

  const abrirWhatsapp = (contato) => {
    const msg = aplicaTemplate(mensagem, contato, cidade, vendedorCidade);
    window.open(montaLinkWhatsapp(contato.telefone, msg), "_blank");
    onSalvar(
      contatos.map((c) => (c.id === contato.id ? { ...c, enviado: true, enviadoTs: Date.now() } : c))
    );
  };

  const remover = (id) => onSalvar(contatos.filter((c) => c.id !== id));
  const desmarcar = (id) => onSalvar(contatos.map((c) => (c.id === id ? { ...c, enviado: false, enviadoTs: null } : c)));

  const enviados = contatos.filter((c) => c.enviado).length;

  return (
    <div
      onClick={onFechar}
      style={{ background: "rgba(10,12,16,0.75)" }}
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4"
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{ background: "#191d25", border: "1px solid #2c3444", maxHeight: "92vh" }}
        className="w-full sm:max-w-2xl rounded-t-2xl sm:rounded-2xl p-4 sm:p-5 flex flex-col gap-4 overflow-hidden"
      >
        <div className="flex items-center justify-between">
          <div>
            <div className="text-base font-semibold text-slate-50">{cidade} <span className="text-slate-500 text-xs font-normal">· {uf} · {segmentoAtual}</span></div>
            <div className="text-[11px] text-slate-500 mt-0.5">{enviados}/{contatos.length} contatos já receberam mensagem</div>
          </div>
          <button onClick={onFechar} className="text-slate-500 hover:text-slate-200 p-2 -m-2"><X size={22} /></button>
        </div>

        <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg" style={{ background: "#14181f", border: "1px solid #2c3444" }}>
          <Users size={14} className="text-slate-500 shrink-0" />
          <span className="text-xs text-slate-400 shrink-0">Vendedor(a) responsável por {cidade}:</span>
          <select
            value={vendedorCidade}
            onChange={(e) => onChangeVendedor(e.target.value)}
            style={{
              background: vendedorCidade ? "#2a2418" : "#1c222c",
              border: "1px solid " + (vendedorCidade ? "#e0a458" : "#2c3444"),
              color: vendedorCidade ? "#e0a458" : "#8b95a6",
            }}
            className="text-sm rounded-lg px-2 py-1.5 flex-1 min-w-0"
          >
            <option value="">ninguém atribuído</option>
            {(vendedores || []).map((v) => (
              <option key={v} value={v}>{v}</option>
            ))}
          </select>
        </div>
        {vendedorCidade && (
          <div className="text-[11px] text-slate-500 -mt-2">
            Use <span className="mono text-slate-300">{"{vendedor}"}</span> na mensagem-padrão do segmento — aqui ela vai sair assinada como <span className="text-[#e0a458]">{vendedorCidade}</span>.
          </div>
        )}

        {!mensagem?.trim() && (
          <div style={{ background: "#2a2418", border: "1px solid #e0a458" }} className="text-[11px] text-[#e0a458] px-3 py-2 rounded-lg">
            Você ainda não definiu a mensagem-padrão deste segmento (botão "mensagem-padrão do segmento" acima). Os links vão abrir o WhatsApp sem texto pronto.
          </div>
        )}

        <div>
          <div className="text-[11px] text-slate-500 mb-1.5">Colar contatos — um por linha, formato "Nome, Telefone" (o telefone também funciona sozinho)</div>
          <textarea
            value={texto}
            onChange={(e) => setTexto(e.target.value)}
            placeholder={"João Silva, 11 91234-5678\nMaria Souza, (11) 98888-7777"}
            rows={3}
            style={{ background: "#14181f", border: "1px solid #2c3444" }}
            className="w-full px-3 py-2 rounded-lg text-slate-200 placeholder-slate-600 text-sm mb-2"
          />
          <button
            onClick={importar}
            disabled={!texto.trim()}
            style={{ background: "#e0a458", color: "#14181f", opacity: texto.trim() ? 1 : 0.4 }}
            className="text-sm font-semibold px-4 py-3 rounded-lg w-full sm:w-auto"
          >
            Importar contatos
          </button>
        </div>

        <div className="overflow-y-auto flex flex-col gap-2" style={{ minHeight: 60 }}>
          {contatos.length === 0 && (
            <div className="text-center text-slate-500 text-sm py-6">Nenhum contato ainda nesta cidade.</div>
          )}
          {contatos.map((c) => (
            <div
              key={c.id}
              style={{ background: c.enviado ? "#1c2a22" : "#14181f", border: "1px solid " + (c.enviado ? "#4f9d69" : "#2c3444") }}
              className="flex items-center gap-2 px-3 py-2.5 rounded-lg"
            >
              <div className="flex-1 min-w-0">
                <div className="text-sm text-slate-100 truncate">{c.nome || "(sem nome)"}</div>
                <div className="mono text-[11px] text-slate-500">{c.telefone}</div>
              </div>
              {c.enviado ? (
                <button
                  onClick={() => desmarcar(c.id)}
                  title="Marcar como não enviado"
                  className="text-xs px-3 py-2.5 rounded-md text-[#4f9d69] flex items-center gap-1 shrink-0"
                >
                  <Check size={14} /> enviado
                </button>
              ) : (
                <button
                  onClick={() => abrirWhatsapp(c)}
                  style={{ background: "#25d366", color: "#0b141a" }}
                  className="text-xs font-semibold px-3.5 py-2.5 rounded-md whitespace-nowrap shrink-0"
                >
                  Abrir WhatsApp
                </button>
              )}
              <button onClick={() => remover(c.id)} className="text-slate-600 hover:text-slate-300 p-2 -m-1 shrink-0"><Trash2 size={16} /></button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function VendedoresView({ data, resumoGlobal, onAdd, onRemove, onDesatribuir, onAtribuir, onIrPara, onVoltar }) {
  const [novoNome, setNovoNome] = useState("");
  const [rankPor, setRankPor] = useState("fechados");

  const estadosOrdenados = useMemo(
    () => Object.entries(STATES_GEO.states).sort((a, b) => a[1].name.localeCompare(b[1].name, "pt-BR")),
    []
  );

  const atribuicoesPorVendedor = useMemo(() => {
    const out = {};
    for (const v of data.vendedores) out[v] = [];
    for (const chave of Object.keys(data.atribuicoes)) {
      const vendedor = data.atribuicoes[chave];
      const [seg, uf] = chave.split("|");
      if (!out[vendedor]) out[vendedor] = [];
      out[vendedor].push({ seg, uf });
    }
    return out;
  }, [data.vendedores, data.atribuicoes]);

  const ranking = useMemo(() => {
    return data.vendedores
      .map((v) => ({
        nome: v,
        fechados: resumoGlobal.porVendedor[v]?.fechados || 0,
        empresas: resumoGlobal.porVendedor[v]?.empresas || 0,
        valor: resumoGlobal.porVendedor[v]?.valor || 0,
      }))
      .sort((a, b) => (rankPor === "valor" ? b.valor - a.valor : b.fechados - a.fechados) || b.empresas - a.empresas);
  }, [data.vendedores, resumoGlobal, rankPor]);

  const submit = () => {
    const n = novoNome.trim();
    if (!n) return;
    onAdd(n);
    setNovoNome("");
  };

  return (
    <div>
      <button onClick={onVoltar} className="flex items-center gap-1 text-sm text-slate-400 hover:text-slate-200 mb-4">
        <ChevronLeft size={15} /> voltar
      </button>
      <div className="text-[11px] mono tracking-widest text-slate-500 uppercase mb-1">
        {data.vendedores.length} vendedor{data.vendedores.length === 1 ? "" : "es"}
      </div>
      <h2 className="text-lg font-semibold text-slate-50 mb-4">Quem cuida do quê</h2>

      {data.vendedores.length > 0 && (
        <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4 mb-5">
          <div className="flex items-center justify-between mb-3">
            <div className="text-xs uppercase tracking-wider text-slate-500">Ranking de vendedores</div>
            <div className="flex items-center gap-1 text-[10px]">
              {[{ v: "fechados", l: "clientes" }, { v: "valor", l: "R$" }].map((o) => (
                <button
                  key={o.v}
                  onClick={() => setRankPor(o.v)}
                  style={{ background: rankPor === o.v ? "#e0a458" : "transparent", color: rankPor === o.v ? "#14181f" : "#8b95a6" }}
                  className="px-2 py-1 rounded-md font-semibold"
                >
                  por {o.l}
                </button>
              ))}
            </div>
          </div>
          <div className="flex flex-col gap-1.5">
            {ranking.map((v, i) => (
              <div key={v.nome} className="flex items-center gap-3 px-3 py-2 rounded-lg" style={{ background: "#191d25" }}>
                <span
                  className="mono text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center shrink-0"
                  style={{
                    background: i === 0 ? "#e0a458" : i === 1 ? "#9aa4b2" : i === 2 ? "#b08968" : "#2c3444",
                    color: i < 3 ? "#14181f" : "#8b95a6",
                  }}
                >
                  {i + 1}
                </span>
                <span className="text-sm text-slate-100 flex-1 truncate">{v.nome}</span>
                <span className="mono text-xs text-slate-400">{v.empresas} empresas</span>
                <span className="mono text-xs text-[#e0a458] font-semibold w-16 text-right">{v.fechados} fech.</span>
                <span className="mono text-xs text-[#4f9d69] font-bold w-20 text-right">{fmtBRL(v.valor)}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="flex items-center gap-2 mb-6">
        <input
          value={novoNome}
          onChange={(e) => setNovoNome(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && submit()}
          placeholder="nome do vendedor"
          style={{ background: "#1c222c", border: "1px solid #2c3444" }}
          className="px-3 py-2 rounded-lg text-sm text-slate-100 placeholder-slate-500 w-56"
        />
        <button onClick={submit} style={{ background: "#e0a458" }} className="px-3.5 py-2 rounded-lg text-sm font-semibold text-[#14181f] flex items-center gap-1.5">
          <Plus size={14} /> adicionar
        </button>
      </div>

      {data.vendedores.length === 0 ? (
        <div style={{ border: "1px dashed #2c3444" }} className="rounded-xl py-10 text-center text-slate-500 text-sm">
          Nenhum vendedor cadastrado ainda. Adicione um nome acima.
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-3">
          {data.vendedores.map((v) => (
            <VendedorCard
              key={v}
              nome={v}
              atribuicoes={atribuicoesPorVendedor[v] || []}
              segmentos={data.ordemSegmentos}
              estados={estadosOrdenados}
              onRemove={() => onRemove(v)}
              onAtribuir={(seg, uf) => onAtribuir(v, seg, uf)}
              onDesatribuir={onDesatribuir}
              onIrPara={onIrPara}
            />
          ))}
        </div>
      )}
    </div>
  );
}

function VendedorCard({ nome, atribuicoes, segmentos, estados, onRemove, onAtribuir, onDesatribuir, onIrPara }) {
  const [segSel, setSegSel] = useState("");
  const [ufSel, setUfSel] = useState("");

  const adicionar = () => {
    if (!segSel || !ufSel) return;
    onAtribuir(segSel, ufSel);
    setSegSel("");
    setUfSel("");
  };

  return (
    <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <div style={{ background: "#2a2418", color: "#e0a458" }} className="w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm shrink-0">
            {nome.trim().charAt(0).toUpperCase()}
          </div>
          <span className="text-slate-100 font-medium">{nome}</span>
        </div>
        <button
          onClick={onRemove}
          title={`Remover ${nome}`}
          className="w-7 h-7 rounded-full flex items-center justify-center text-slate-600 hover:text-[#e08a8a] hover:bg-[#3a1e1e]"
        >
          <Trash2 size={13} />
        </button>
      </div>

      <div className="flex flex-wrap items-center gap-1.5 mb-3">
        <select
          value={segSel}
          onChange={(e) => setSegSel(e.target.value)}
          style={{ background: "#14181f", border: "1px solid #2c3444" }}
          className="text-xs text-slate-200 rounded-lg px-2 py-1.5 flex-1 min-w-[140px]"
        >
          <option value="">segmento…</option>
          {segmentos.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>
        <select
          value={ufSel}
          onChange={(e) => setUfSel(e.target.value)}
          style={{ background: "#14181f", border: "1px solid #2c3444" }}
          className="text-xs text-slate-200 rounded-lg px-2 py-1.5 w-24"
        >
          <option value="">estado…</option>
          {estados.map(([uf, s]) => (
            <option key={uf} value={uf}>{s.name}</option>
          ))}
        </select>
        <button
          onClick={adicionar}
          disabled={!segSel || !ufSel}
          style={{
            background: segSel && ufSel ? "#e0a458" : "#232a36",
            color: segSel && ufSel ? "#14181f" : "#5b6579",
          }}
          className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0"
        >
          <Plus size={14} />
        </button>
      </div>

      {atribuicoes.length === 0 ? (
        <div className="text-[11px] text-slate-500 italic">{nome} ainda não cuida de nenhum segmento/estado</div>
      ) : (
        <div className="flex flex-col gap-1.5">
          {atribuicoes.map(({ seg, uf }) => (
            <div key={seg + uf} className="flex items-center gap-2 text-xs">
              <button
                onClick={() => onIrPara(seg, uf)}
                className="flex-1 text-left px-2.5 py-1.5 rounded-lg hover:bg-[#20262f] flex items-center gap-1.5 text-slate-300"
                style={{ background: "#191d25" }}
              >
                <span className="text-slate-100">{seg}</span>
                <span className="mono text-[10px] text-[#e0a458]">{uf}</span>
              </button>
              <button
                onClick={() => onDesatribuir(seg, uf)}
                title="Tirar atribuição"
                className="w-6 h-6 rounded-full flex items-center justify-center text-slate-600 hover:text-[#e08a8a]"
              >
                <X size={11} />
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function ChartTooltip({ active, payload, label }) {
  if (!active || !payload || !payload.length) return null;
  return (
    <div style={{ background: "#20262f", border: "1px solid #3a4252" }} className="rounded-lg px-3 py-2 text-xs shadow-xl">
      <div className="text-slate-200 font-semibold mb-1">{label}</div>
      {payload.map((p) => (
        <div key={p.dataKey} className="flex items-center gap-1.5" style={{ color: p.color }}>
          <span className="w-2 h-2 rounded-full inline-block" style={{ background: p.color }} />
          {p.name}: <span className="mono font-bold">{p.value}</span>
        </div>
      ))}
    </div>
  );
}

function PainelGeralView({ data, resumoPorSegmento, resumoGlobal, onIrParaSegmento, onExportar, onVoltar, onSetMeta }) {
  const taxaConversao = resumoGlobal.totalEmpresas > 0 ? ((resumoGlobal.totalFechados / resumoGlobal.totalEmpresas) * 100) : 0;
  const ticketMedio = resumoGlobal.totalFechados > 0 ? (resumoGlobal.totalValor / resumoGlobal.totalFechados) : 0;
  const [rankPor, setRankPor] = useState("fechados");
  const [metaInput, setMetaInput] = useState(String(data.meta || ""));

  const dadosSegmentos = useMemo(() => {
    return data.ordemSegmentos
      .map((s) => ({
        nome: s.length > 26 ? s.slice(0, 24) + "…" : s,
        nomeCompleto: s,
        fechados: resumoPorSegmento[s]?.fechados || 0,
        empresas: resumoPorSegmento[s]?.empresas || 0,
        valor: resumoPorSegmento[s]?.valor || 0,
      }))
      .filter((d) => d.empresas > 0 || d.fechados > 0)
      .sort((a, b) => b.fechados - a.fechados || b.empresas - a.empresas)
      .slice(0, 8);
  }, [data.ordemSegmentos, resumoPorSegmento]);

  const dadosConversao = useMemo(() => {
    return data.ordemSegmentos
      .map((s) => ({
        nome: s.length > 22 ? s.slice(0, 20) + "…" : s,
        empresas: resumoPorSegmento[s]?.empresas || 0,
        taxa: resumoPorSegmento[s]?.empresas > 0 ? +((resumoPorSegmento[s].fechados / resumoPorSegmento[s].empresas) * 100).toFixed(1) : 0,
      }))
      .filter((d) => d.empresas >= 3)
      .sort((a, b) => b.taxa - a.taxa)
      .slice(0, 8);
  }, [data.ordemSegmentos, resumoPorSegmento]);

  const dadosEvolucao = useMemo(() => {
    const eventos = [...(data.historico || [])].filter((e) => e.tipo === "fechado").sort((a, b) => a.ts - b.ts);
    if (eventos.length === 0) return [];
    const porDia = {};
    for (const e of eventos) {
      const dia = new Date(e.ts).toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit" });
      if (!porDia[dia]) porDia[dia] = { dia, fechados: 0, valor: 0 };
      porDia[dia].fechados += e.qtd || 0;
      porDia[dia].valor += e.valorDelta || 0;
    }
    let acumF = 0, acumV = 0;
    return Object.values(porDia).map((d) => {
      acumF += d.fechados;
      acumV += d.valor;
      return { dia: d.dia, fechados: acumF, valor: acumV };
    });
  }, [data.historico]);

  const dadosVendedores = useMemo(() => {
    return data.vendedores
      .map((v) => ({
        nome: v,
        fechados: resumoGlobal.porVendedor[v]?.fechados || 0,
        empresas: resumoGlobal.porVendedor[v]?.empresas || 0,
        valor: resumoGlobal.porVendedor[v]?.valor || 0,
      }))
      .sort((a, b) => (rankPor === "valor" ? b.valor - a.valor : b.fechados - a.fechados) || b.empresas - a.empresas);
  }, [data.vendedores, resumoGlobal, rankPor]);

  const dadosEstados = useMemo(() => {
    return Object.entries(resumoGlobal.porEstado)
      .map(([uf, v]) => ({ uf, empresas: v.empresas, fechados: v.fechados, valor: v.valor }))
      .sort((a, b) => b.empresas - a.empresas)
      .slice(0, 10);
  }, [resumoGlobal]);

  const funil = [
    { label: STATUS_OPTS[0].label, value: resumoGlobal.totalNaoIniciado, color: STATUS_OPTS[0].color },
    { label: STATUS_OPTS[1].label, value: resumoGlobal.totalAndamento, color: STATUS_OPTS[1].color },
    { label: STATUS_OPTS[2].label, value: resumoGlobal.totalConcluidas, color: STATUS_OPTS[2].color },
  ];
  const funilMax = Math.max(1, ...funil.map((f) => f.value));
  const atividade = (data.historico || []).slice(0, 8);

  return (
    <div>
      <button onClick={onVoltar} className="flex items-center gap-1 text-sm text-slate-400 hover:text-slate-200 mb-4">
        <ChevronLeft size={15} /> voltar
      </button>
      <div className="flex items-center justify-between flex-wrap gap-2 mb-1">
        <div className="text-[11px] mono tracking-widest text-slate-500 uppercase">visão consolidada · todos os segmentos</div>
        <button
          onClick={onExportar}
          style={{ background: "#1c222c", border: "1px solid #2c3444", color: "#c3cad6" }}
          className="px-3 py-1.5 rounded-lg text-xs font-medium flex items-center gap-1.5"
        >
          <Download size={12} /> exportar CSV
        </button>
      </div>
      <h2 className="text-lg font-semibold text-slate-50 mb-5">Painel geral</h2>

      <div className="grid grid-cols-2 sm:grid-cols-7 gap-3 mb-6">
        {[
          { label: "empresas prospectadas", value: resumoGlobal.totalEmpresas.toLocaleString("pt-BR") },
          { label: "clientes fechados", value: resumoGlobal.totalFechados.toLocaleString("pt-BR"), destaque: true },
          { label: "valor fechado", value: fmtBRL(resumoGlobal.totalValor), destaque: true },
          { label: "ticket médio", value: fmtBRL(ticketMedio) },
          { label: "taxa de conversão", value: taxaConversao.toFixed(1) + "%" },
          { label: "cidades mapeadas", value: resumoGlobal.totalCidades.toLocaleString("pt-BR") },
          { label: "vendedores ativos", value: data.vendedores.length },
        ].map((it) => (
          <div key={it.label} style={{ background: "#1c222c", border: "1px solid " + (it.destaque ? "#3a6b4c" : "#232a36") }} className="rounded-xl px-4 py-3">
            <div className="mono text-xl sm:text-2xl font-bold" style={{ color: it.destaque ? "#4f9d69" : "#f8fafc" }}>{it.value}</div>
            <div className="text-[10px] sm:text-[11px] text-slate-500 mt-0.5">{it.label}</div>
          </div>
        ))}
      </div>

      <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4 mb-4">
        <div className="flex items-center justify-between flex-wrap gap-2 mb-2">
          <div className="text-xs uppercase tracking-wider text-slate-500">Meta de faturamento</div>
          <div className="flex items-center gap-1.5">
            <span className="text-xs text-slate-500">R$</span>
            <input
              value={metaInput}
              onChange={(e) => setMetaInput(e.target.value.replace(/[^0-9]/g, ""))}
              onBlur={() => onSetMeta(metaInput)}
              onKeyDown={(e) => e.key === "Enter" && onSetMeta(metaInput)}
              placeholder="definir meta"
              inputMode="numeric"
              style={{ background: "#14181f", border: "1px solid #2c3444" }}
              className="mono w-28 px-2 py-1 rounded-lg text-xs text-slate-100"
            />
          </div>
        </div>
        {data.meta > 0 ? (
          <>
            <div className="rounded-full h-3 mb-1.5" style={{ background: "#14181f" }}>
              <div
                className="h-3 rounded-full transition-all"
                style={{ width: `${Math.min(100, (resumoGlobal.totalValor / data.meta) * 100)}%`, background: resumoGlobal.totalValor >= data.meta ? "#4f9d69" : "#e0a458", minWidth: resumoGlobal.totalValor > 0 ? 6 : 0 }}
              />
            </div>
            <div className="text-[11px] text-slate-500">
              {fmtBRL(resumoGlobal.totalValor)} de {fmtBRL(data.meta)} · {((resumoGlobal.totalValor / data.meta) * 100).toFixed(0)}%
            </div>
          </>
        ) : (
          <div className="text-[11px] text-slate-500 italic">defina uma meta em R$ pra acompanhar o progresso aqui</div>
        )}
      </div>

      <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4 mb-4">
        <div className="text-xs uppercase tracking-wider text-slate-500 mb-3">Funil de prospecção — todas as cidades registradas</div>
        <div className="flex flex-col gap-2.5">
          {funil.map((f) => (
            <div key={f.label} className="flex items-center gap-3">
              <span className="text-xs text-slate-400 w-40 shrink-0">{f.label}</span>
              <div className="flex-1 rounded-full h-3" style={{ background: "#14181f" }}>
                <div className="h-3 rounded-full transition-all" style={{ width: `${(f.value / funilMax) * 100}%`, background: f.color, minWidth: f.value > 0 ? 6 : 0 }} />
              </div>
              <span className="mono text-xs font-bold w-10 text-right" style={{ color: f.color }}>{f.value}</span>
            </div>
          ))}
        </div>
      </div>

      <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4 mb-4">
        <div className="text-xs uppercase tracking-wider text-slate-500 mb-3 flex items-center gap-1.5">
          <TrendingUp size={13} /> Evolução de fechamentos e faturamento
        </div>
        {dadosEvolucao.length < 2 ? (
          <div className="text-sm text-slate-500 italic py-10 text-center">
            precisa de fechamentos em pelo menos 2 dias diferentes pra desenhar a evolução
          </div>
        ) : (
          <ResponsiveContainer width="100%" height={240}>
            <LineChart data={dadosEvolucao} margin={{ left: 0, right: 8, top: 4, bottom: 4 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#232a36" vertical={false} />
              <XAxis dataKey="dia" tick={{ fill: "#5b6579", fontSize: 11 }} axisLine={{ stroke: "#232a36" }} tickLine={false} />
              <YAxis yAxisId="fechados" tick={{ fill: "#e0a458", fontSize: 11 }} axisLine={false} tickLine={false} allowDecimals={false} width={30} />
              <YAxis yAxisId="valor" orientation="right" tick={{ fill: "#4f9d69", fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={(v) => fmtBRL(v)} width={60} />
              <RTooltip content={<ChartTooltip />} cursor={{ stroke: "#3a4252" }} />
              <Line yAxisId="fechados" type="monotone" dataKey="fechados" name="Clientes fechados (acum.)" stroke="#e0a458" strokeWidth={2} dot={{ r: 3, fill: "#e0a458" }} />
              <Line yAxisId="valor" type="monotone" dataKey="valor" name="Faturamento (acum.)" stroke="#4f9d69" strokeWidth={2} dot={{ r: 3, fill: "#4f9d69" }} />
            </LineChart>
          </ResponsiveContainer>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-4">
        <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4">
          <div className="text-xs uppercase tracking-wider text-slate-500 mb-3 flex items-center gap-1.5">
            <TrendingUp size={13} /> Top segmentos por fechamentos
          </div>
          {dadosSegmentos.length === 0 ? (
            <div className="text-sm text-slate-500 italic py-10 text-center">ainda sem dados registrados</div>
          ) : (
            <ResponsiveContainer width="100%" height={Math.max(180, dadosSegmentos.length * 34)}>
              <BarChart data={dadosSegmentos} layout="vertical" margin={{ left: 8, right: 16, top: 4, bottom: 4 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#232a36" horizontal={false} />
                <XAxis type="number" tick={{ fill: "#5b6579", fontSize: 11 }} axisLine={{ stroke: "#232a36" }} tickLine={false} allowDecimals={false} />
                <YAxis type="category" dataKey="nome" tick={{ fill: "#c3cad6", fontSize: 11 }} axisLine={false} tickLine={false} width={150} />
                <RTooltip content={<ChartTooltip />} cursor={{ fill: "#20262f" }} />
                <Bar dataKey="empresas" name="Empresas" fill="#3a4252" radius={[0, 4, 4, 0]} barSize={10} />
                <Bar dataKey="fechados" name="Fechados" fill="#4f9d69" radius={[0, 4, 4, 0]} barSize={10}>
                  {dadosSegmentos.map((d, i) => (
                    <Cell key={i} onClick={() => onIrParaSegmento(d.nomeCompleto)} style={{ cursor: "pointer" }} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>

        <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="text-xs uppercase tracking-wider text-slate-500 flex items-center gap-1.5">
              <Users size={13} /> Ranking de vendedores
            </div>
            <div className="flex items-center gap-1 text-[10px]">
              {[{ v: "fechados", l: "clientes" }, { v: "valor", l: "R$" }].map((o) => (
                <button
                  key={o.v}
                  onClick={() => setRankPor(o.v)}
                  style={{
                    background: rankPor === o.v ? "#e0a458" : "transparent",
                    color: rankPor === o.v ? "#14181f" : "#8b95a6",
                  }}
                  className="px-2 py-1 rounded-md font-semibold"
                >
                  por {o.l}
                </button>
              ))}
            </div>
          </div>
          {dadosVendedores.length === 0 ? (
            <div className="text-sm text-slate-500 italic py-10 text-center">cadastre vendedores e atribua segmento + estado pra ver aqui</div>
          ) : (
            <>
              {dadosVendedores.some((d) => d.fechados > 0 || d.valor > 0) && (
                <div className="flex items-center gap-2 mb-4">
                  {dadosVendedores.slice(0, 3).map((v, i) => (
                    <div key={v.nome} className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg flex-1" style={{ background: "#191d25" }}>
                      <span
                        className="mono text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center shrink-0"
                        style={{
                          background: i === 0 ? "#e0a458" : i === 1 ? "#9aa4b2" : "#b08968",
                          color: "#14181f",
                        }}
                      >
                        {i + 1}
                      </span>
                      <span className="text-xs text-slate-200 truncate">{v.nome}</span>
                      <span className="mono text-xs text-[#4f9d69] font-bold ml-auto">
                        {rankPor === "valor" ? fmtBRL(v.valor) : v.fechados}
                      </span>
                    </div>
                  ))}
                </div>
              )}
              <ResponsiveContainer width="100%" height={Math.max(160, dadosVendedores.length * 34)}>
                <BarChart data={dadosVendedores} layout="vertical" margin={{ left: 8, right: 16, top: 4, bottom: 4 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#232a36" horizontal={false} />
                  <XAxis type="number" tick={{ fill: "#5b6579", fontSize: 11 }} axisLine={{ stroke: "#232a36" }} tickLine={false} allowDecimals={false} />
                  <YAxis type="category" dataKey="nome" tick={{ fill: "#c3cad6", fontSize: 11 }} axisLine={false} tickLine={false} width={90} />
                  <RTooltip content={<ChartTooltip />} cursor={{ fill: "#20262f" }} />
                  {rankPor === "valor" ? (
                    <Bar dataKey="valor" name="Valor (R$)" fill="#4f9d69" radius={[0, 4, 4, 0]} barSize={12} />
                  ) : (
                    <>
                      <Bar dataKey="empresas" name="Empresas" fill="#3a4252" radius={[0, 4, 4, 0]} barSize={10} />
                      <Bar dataKey="fechados" name="Fechados" fill="#e0a458" radius={[0, 4, 4, 0]} barSize={10} />
                    </>
                  )}
                </BarChart>
              </ResponsiveContainer>
            </>
          )}
        </div>
      </div>

      <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4 mb-4">
        <div className="text-xs uppercase tracking-wider text-slate-500 mb-3">Taxa de conversão por segmento (%)</div>
        {dadosConversao.length === 0 ? (
          <div className="text-sm text-slate-500 italic py-10 text-center">precisa de pelo menos 3 empresas registradas num segmento pra calcular</div>
        ) : (
          <ResponsiveContainer width="100%" height={Math.max(180, dadosConversao.length * 32)}>
            <BarChart data={dadosConversao} layout="vertical" margin={{ left: 8, right: 24, top: 4, bottom: 4 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#232a36" horizontal={false} />
              <XAxis type="number" tick={{ fill: "#5b6579", fontSize: 11 }} axisLine={{ stroke: "#232a36" }} tickLine={false} unit="%" />
              <YAxis type="category" dataKey="nome" tick={{ fill: "#c3cad6", fontSize: 11 }} axisLine={false} tickLine={false} width={140} />
              <RTooltip content={<ChartTooltip />} cursor={{ fill: "#20262f" }} />
              <Bar dataKey="taxa" name="Conversão" fill="#e0a458" radius={[0, 4, 4, 0]} barSize={12}>
                <LabelList dataKey="taxa" position="right" formatter={(v) => v + "%"} fill="#c3cad6" fontSize={11} />
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        )}
      </div>

      <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4 mb-4">
        <div className="text-xs uppercase tracking-wider text-slate-500 mb-3">Empresas prospectadas × fechadas por estado</div>
        {dadosEstados.length === 0 ? (
          <div className="text-sm text-slate-500 italic py-10 text-center">ainda sem dados registrados</div>
        ) : (
          <ResponsiveContainer width="100%" height={260}>
            <BarChart data={dadosEstados} margin={{ left: 0, right: 16, top: 4, bottom: 4 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#232a36" vertical={false} />
              <XAxis dataKey="uf" tick={{ fill: "#c3cad6", fontSize: 11 }} axisLine={{ stroke: "#232a36" }} tickLine={false} />
              <YAxis tick={{ fill: "#5b6579", fontSize: 11 }} axisLine={false} tickLine={false} allowDecimals={false} />
              <RTooltip content={<ChartTooltip />} cursor={{ fill: "#20262f" }} />
              <Bar dataKey="empresas" name="Empresas" fill="#3a4252" radius={[4, 4, 0, 0]} />
              <Bar dataKey="fechados" name="Fechados" fill="#4f9d69" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        )}
      </div>

      <div style={{ background: "#1c222c", border: "1px solid #232a36" }} className="rounded-2xl p-4">
        <div className="text-xs uppercase tracking-wider text-slate-500 mb-3">Atividade recente</div>
        {atividade.length === 0 ? (
          <div className="text-sm text-slate-500 italic py-6 text-center">nenhum fechamento ou conclusão registrado ainda</div>
        ) : (
          <div className="flex flex-col gap-2">
            {atividade.map((ev, i) => (
              <div key={i} className="flex items-center gap-2.5 text-xs">
                <span
                  className="w-2 h-2 rounded-full shrink-0"
                  style={{ background: ev.tipo === "fechado" ? "#4f9d69" : "#e0a458" }}
                />
                <span className="text-slate-300">
                  {ev.tipo === "fechado" ? (
                    <>
                      {ev.qtd > 0 && <>fechou <span className="text-[#4f9d69] font-semibold">{ev.qtd} cliente{ev.qtd > 1 ? "s" : ""}</span></>}
                      {ev.qtd > 0 && ev.valorDelta > 0 && " · "}
                      {ev.valorDelta > 0 && <span className="text-[#e0a458] font-semibold">{fmtBRL(ev.valorDelta)}</span>}
                      {" "}em
                    </>
                  ) : (
                    <>marcou como <span className="text-[#e0a458] font-semibold">concluído</span></>
                  )}
                  {" "}
                  <span className="text-slate-100">{ev.cidade}</span>
                  <span className="mono text-[10px] text-slate-500"> ({ev.uf})</span> · {ev.seg}
                </span>
                <span className="mono text-[10px] text-slate-600 ml-auto shrink-0">{fmtRelTime(ev.ts)}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
